class User {
  final String id;
  final String name;
  final String email;
  final String token; // Authentication token, e.g., JWT

  User({
    required this.id,
    required this.name,
    required this.email,
    required this.token,
  });

  // Factory constructor to create a User from a JSON map
  factory User.fromJson(Map<String, dynamic> json) {
    return User(
      id: json['id'] as String,
      name: json['name'] as String,
      email: json['email'] as String,
      token: json['token'] as String,
    );
  }

  // Convert a User object to a JSON map
  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'email': email,
      'token': token,
    };
  }
}

// File: auth_service.dart
// This file contains the AuthService, managing authentication state and session persistence.

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'user.dart'; // Import the User model

class AuthService extends ChangeNotifier {
  User? _currentUser;
  bool _isAuthenticated = false;
  bool _isLoading = true; // Indicates if the initial session loading is in progress

  // Key for storing user data in SharedPreferences
  static const String _keyUserData = 'user_data';

  AuthService() {
    // Attempt to load the session when the service is initialized
    _loadSession();
  }

  User? get currentUser => _currentUser;
  bool get isAuthenticated => _isAuthenticated;
  bool get isLoading => _isLoading;

  // Loads the user session from shared_preferences
  Future<void> _loadSession() async {
    _isLoading = true;
    notifyListeners(); // Notify that loading has started

    try {
      final prefs = await SharedPreferences.getInstance();
      final userDataString = prefs.getString(_keyUserData);

      if (userDataString != null) {
        // Decode the JSON string back into a User object
        final Map<String, dynamic> userMap = json.decode(userDataString);
        _currentUser = User.fromJson(userMap);
        _isAuthenticated = true;
      } else {
        _isAuthenticated = false;
        _currentUser = null;
      }
    } catch (e) {
      debugPrint("Error loading session: $e");
      _isAuthenticated = false;
      _currentUser = null;
    } finally {
      _isLoading = false;
      notifyListeners(); // Notify that loading has finished and state might have changed
    }
  }

  // Saves the current user's data to shared_preferences
  Future<void> _saveSession(User user) async {
    final prefs = await SharedPreferences.getInstance();
    // Encode the User object to a JSON string before saving
    final String userDataString = json.encode(user.toJson());
    await prefs.setString(_keyUserData, userDataString);
  }

  // Clears the user session from shared_preferences
  Future<void> _clearSession() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove(_keyUserData);
  }

  // Simulates a login API call
  Future<bool> login(String username, String password) async {
    _isLoading = true;
    notifyListeners(); // Indicate that an async operation is starting

    try {
      await Future.delayed(const Duration(seconds: 2)); // Simulate network delay

      // Simulate successful login with dummy data
      if (username == 'test' && password == 'password') {
        final newUser = User(
          id: 'user_123',
          name: 'Test User',
          email: 'test@example.com',
          token: 'jwt_token_12345', // In a real app, this would come from the API
        );

        _currentUser = newUser;
        _isAuthenticated = true;
        await _saveSession(newUser); // Persist session
        return true;
      } else {
        // Simulate failed login
        debugPrint('Login failed: Invalid credentials');
        _isAuthenticated = false;
        _currentUser = null;
        return false;
      }
    } catch (e) {
      debugPrint('Login error: $e');
      _isAuthenticated = false;
      _currentUser = null;
      return false;
    } finally {
      _isLoading = false;
      notifyListeners(); // Notify all listeners about the change in authentication state
    }
  }

  // Logs out the current user and clears the session
  Future<void> logout() async {
    _isLoading = true;
    notifyListeners(); // Indicate that an async operation is starting

    try {
      await _clearSession(); // Clear persisted session
      _currentUser = null;
      _isAuthenticated = false;
    } catch (e) {
      debugPrint("Error during logout: $e");
    } finally {
      _isLoading = false;
      notifyListeners(); // Notify all listeners about the change in authentication state
    }
  }
}

// File: main.dart
// This file sets up the Flutter application, integrating AuthService with Provider.

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import 'auth_service.dart'; // Import AuthService
import 'user.dart'; // Import User model (though not directly used in main, good practice)

void main() {
  runApp(
    // Provide the AuthService to the widget tree
    ChangeNotifierProvider(
      create: (context) => AuthService(),
      child: const MyApp(),
    ),
  );
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Auth Manager',
      theme: ThemeData(
        primarySwatch: Colors.blue,
        visualDensity: VisualDensity.adaptivePlatformDensity,
      ),
      // Use Consumer to react to changes in AuthService state
      home: Consumer<AuthService>(
        builder: (context, authService, _) {
          if (authService.isLoading) {
            // Show a splash screen or loading indicator while the session is being loaded
            return const SplashScreen();
          } else {
            // Navigate to Home screen if authenticated, otherwise to Login screen
            return authService.isAuthenticated ? const HomeScreen() : const LoginScreen();
          }
        },
      ),
    );
  }
}

